mapper.select:
SELECT
FROM lodging l LEFT JOIN lodging_amenity la ON la.lodging_id = l.lodging_id LEFT JOIN amenity a ON a.amenity_id = la.amenity_id WHERE 1 = 1
AND l.monthly_price <= #{priceMax}
GROUP BY l.lodging_id
HAVING SUM(CASE WHEN LOWER(a.amenity_name) LIKE '%wifi%' OR LOWER(a.amenity_name) LIKE '%wi-fi%' OR a.amenity_name LIKE '%와이파이%' THEN 1 ELSE 0 END) > 0
ORDER BY l.average_rating DESC, l.review_total DESC, l.monthly_price ASC LIMIT #{limit}
